@timeout_handler(timeout=120)
async def text_browser_view(url: str, description: str):
    # If the official internal reading service is configured, use it.
    # Otherwise fall back to direct HTTP fetching + HTML text extraction.
    search_tool_api_url = os.getenv("SEARCH_TOOL_API_URL", "").strip()
    if not search_tool_api_url:
        if not url or not url.startswith("http"):
            return InternalResponse(
                error=return_error(
                    error_msg="error: url is empty or not a valid http(s) url",
                    verbose=True,
                    req=url,
                    context="",
                )
            )
        try:
            parsed = urlparse(url)
            referer = f"{parsed.scheme}://{parsed.netloc}/" if parsed.scheme and parsed.netloc else ""
            # We keep headers simple but slightly more browser-like to reduce 403.
            headers_base = {
                "Accept": "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8",
                "Accept-Language": "en-US,en;q=0.9,zh-CN;q=0.8,zh;q=0.7",
                "Cache-Control": "no-cache",
                "Pragma": "no-cache",
            }
            user_agents = [
                "Mozilla/5.0 (X11; Linux x86_64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0 Safari/537.36",
                "Mozilla/5.0 (Macintosh; Intel Mac OS X 13_6) AppleWebKit/605.1.15 (KHTML, like Gecko) Version/17.2 Safari/605.1.15",
                "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0 Safari/537.36",
            ]
            async def _fetch_html(target_url: str) -> tuple[str, str]:
                """
                Returns (html, content_type). Raises on non-2xx unless explicitly handled by caller.
                """
                timeout = aiohttp.ClientTimeout(total=60)
                async with aiohttp.ClientSession(timeout=timeout, trust_env=True) as session:
                    last_exc: Exception | None = None
                    for i, ua in enumerate(user_agents, start=1):
                        headers = dict(headers_base)
                        headers["User-Agent"] = ua
                        if referer:
                            headers["Referer"] = referer
                        try:
                            async with session.get(
                                target_url,
                                headers=headers,
                                allow_redirects=True,
                            ) as resp:
                                status = resp.status
                                content_type = (resp.headers.get("Content-Type") or "").lower()
                                logger.info(
                                    f"[text_browser_view] fetch try={i} status={status} url={target_url} ct={content_type[:64]}"
                                )
                                # NOTE: PDF parsing is not implemented locally.
                                if "application/pdf" in content_type or target_url.lower().endswith(".pdf"):
                                    return (
                                        "",
                                        "application/pdf",
                                    )
                                resp.raise_for_status()
                                html = await resp.text(errors="ignore")
                                return html, content_type
                        except Exception as e:
                            last_exc = e
                            # Retry on 403/429/5xx could be helpful; for other errors, retry once anyway.
                            continue
                    assert last_exc is not None
                    raise last_exc
            html = ""
            content_type = ""
            try:
                html, content_type = await _fetch_html(url)
            except Exception as e:
                # Optional fallback: use jina.ai to fetch a text-rendered version, which can bypass some blocks.
                use_jina = os.getenv("TEXT_BROWSER_USE_JINA_FALLBACK", "1").strip() not in ["0", "false", "False"]
                if use_jina:
                    jina_url = f"https://r.jina.ai/{url}"
                    logger.warning(f"[text_browser_view] direct fetch failed, trying jina fallback: {jina_url} err={e}")
                    try:
                        html, content_type = await _fetch_html(jina_url)
                    except Exception:
                        raise e
                else:
                    raise e
            if "application/pdf" in content_type or url.lower().endswith(".pdf"):
                return InternalResponse(
                    data=(
                        "PDF content detected, but local PDF parsing is not implemented. "
                        "Please use an internal TextBrowserView service or add a PDF parser."
                    )
                )
            soup = BeautifulSoup(html, "html.parser")
            # Remove scripts/styles.
            for tag in soup(["script", "style", "noscript"]):
                tag.decompose()
            text = soup.get_text("\n")
            # Normalize whitespace and truncate to keep context manageable.
            lines = [ln.strip() for ln in text.splitlines()]
            lines = [ln for ln in lines if ln]
            text = "\n".join(lines)
            try:
                max_chars = int(os.getenv("TEXT_BROWSER_MAX_CHARS", "20000"))
            except Exception:
                max_chars = 20000
            if len(text) > max_chars:
                text = text[:max_chars] + "\n...[truncated]..."
            return InternalResponse(data=text)
        except Exception:
            return InternalResponse(
                error=return_error(
                    "SYSTEM_ERROR",
                    verbose=True,
                    req=url,
                    context=traceback.format_exc(),
                )
            )
